import React, { useState, useRef, useEffect } from 'react';
import { classifyWaste, IMPACT, OBJECT_IMPACT } from '../services/api';
import { addRecord, isDuplicate, claimDailyBonus, ECO_POINTS, calcGreenCredits } from '../services/store';
import ResultCard from '../components/ResultCard';
import ImpactPanel from '../components/ImpactPanel';
import ParticleRing from '../components/ParticleRing';
import useScrollReveal from '../hooks/useScrollReveal';
import './Home.css';

const CAT_COLOR = {
  Recyclable: '#60a5fa', Hazardous: '#f87171', Biodegradable: '#4ade80',
};
const CAT_ICON = {
  Recyclable: '♻️', Hazardous: '☢️', Biodegradable: '🌿',
};
const CIRC = 653;

export default function Home() {
  const [preview, setPreview] = useState(null);
  const [file, setFile] = useState(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState('');
  const [toast, setToast] = useState(null);
  const [ripple, setRipple] = useState(false);
  const [isDrag, setIsDrag] = useState(false);
  const inputRef = useRef();
  const ringRef = useRef();

  /* ── Subtitle typewriter ── */
  const SUBTITLE = 'AI Waste Intelligence';
  const [typedSub, setTypedSub] = useState('');
  useEffect(() => {
    let i = 0;
    const iv = setInterval(() => {
      setTypedSub(SUBTITLE.slice(0, i + 1));
      i++;
      if (i >= SUBTITLE.length) clearInterval(iv);
    }, 55);
    return () => clearInterval(iv);
  }, []);

  function showToast(msg, type = 'success') {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 3000);
  }

  function handleFileChange(e) {
    const f = e.target.files?.[0] || e.dataTransfer?.files?.[0];
    if (!f) return;
    if (!f.type.startsWith('image/')) { showToast('Please select an image file', 'error'); return; }
    setFile(f); setResult(null); setError('');
    const reader = new FileReader();
    reader.onload = ev => setPreview(ev.target.result);
    reader.readAsDataURL(f);
  }

  /* Tap ripple before opening file picker */
  function handleRingClick(e) {
    if (loading || result) return;
    setRipple(true);
    setTimeout(() => setRipple(false), 600);
  }

  /* Drag & drop */
  function handleDragOver(e) { e.preventDefault(); setIsDrag(true); }
  function handleDragLeave() { setIsDrag(false); }
  function handleDrop(e) {
    e.preventDefault(); setIsDrag(false);
    handleFileChange({ target: {}, dataTransfer: e.dataTransfer });
  }

  async function handleSubmit(e) {
    e.preventDefault();
    if (!file) { showToast('Select or capture an image first', 'error'); return; }
    const duplicate = isDuplicate(file);
    setLoading(true); setError(''); setResult(null);
    try {
      const data = await classifyWaste(file);
      const category = data.prediction;
      const impact = IMPACT[category];
      if (!impact) throw new Error('Unknown category: ' + category);
      const objectKey = (data.object || '').toLowerCase();
      const objectMetrics = OBJECT_IMPACT[objectKey] || {};
      const co2Saved = objectMetrics.co2Saved !== undefined ? objectMetrics.co2Saved : (impact.co2Saved || 0);
      const objectDetected = data.object || null;
      const earned = duplicate ? 0 : (ECO_POINTS[category] || 5);
      const gotBonus = duplicate ? false : claimDailyBonus();
      const totalPts = earned + (gotBonus ? ECO_POINTS.DailyBonus : 0);
      const greenCredits = duplicate ? 0 : calcGreenCredits(co2Saved, category);
      const record = duplicate ? null : addRecord(category, objectMetrics.guidance || impact.guidance, file, co2Saved, objectDetected);

      setResult({
        category,
        impact: {
          ...impact,
          ...objectMetrics,
          detectedObject: data.object || data.detectedObject || null,
          confidence: data.confidence != null ? Number(data.confidence) : null,
        },
        record,
        ecoPoints: earned,
        bonusPoints: gotBonus ? ECO_POINTS.DailyBonus : 0,
        greenCredits,
        co2Saved,
      });

      if (duplicate) {
        showToast('Duplicate — classified, no eco-points awarded.', 'error');
      } else {
        showToast(`+${totalPts} eco-points earned! 🌱`);
      }
    } catch (err) {
      setError(err.message || 'Something went wrong. Is the server running?');
      showToast(err.message || 'Error', 'error');
    } finally { setLoading(false); }
  }

  function handleReset() {
    setPreview(null); setFile(null); setResult(null); setError('');
    if (inputRef.current) inputRef.current.value = '';
  }

  const confidence = result?.impact?.confidence ?? null;
  const ringOffset = confidence !== null ? CIRC * (1 - confidence) : 0;
  const catIcon = result ? (CAT_ICON[result.category] || '🗑️') : null;
  const catColor = result ? (CAT_COLOR[result.category] || '#00FF87') : null;
  const ringMode = loading ? 'loading' : result ? 'result' : 'idle';

  useScrollReveal([result, preview]);

  return (
    <div className="page-content home-page">

      {/* ── Header ── */}
      <header className="home-header">
        <div className="home-header-left">
          <span className="home-live-badge">
            <span className="live-dot" />
            <span className="live-dot live-dot-ping" />
            LIVE
          </span>
          <h1 className="home-wordmark">
            VERDANT<span className="wordmark-dot">.</span>
          </h1>
          <p className="home-subtitle" aria-label={SUBTITLE}>
            {typedSub}<span className="subtitle-cursor">|</span>
          </p>
        </div>
        <div className="home-avatar">
          <div className="avatar-ring" />
          <span className="avatar-icon">🌿</span>
        </div>
      </header>

      {/* ── Ring Hero ── */}
      <section
        className={`ring-hero${isDrag ? ' ring-hero-drag' : ''}`}
        data-reveal="scale"
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
      >
        <div
          className="scan-ring-wrap"
          ref={ringRef}
          onClick={handleRingClick}
        >
          {/* File input overlay */}
          {!loading && !result && (
            <input
              type="file"
              accept="image/*"
              ref={inputRef}
              onChange={handleFileChange}
              title="Tap to scan waste"
            />
          )}

          {/* Orbiting particles */}
          <ParticleRing mode={ringMode} resultColor={catColor} />

          {/* Tap ripple */}
          {ripple && <div className="ring-ripple" />}

          {/* SVG confidence ring */}
          <svg className="scan-ring-svg" viewBox="0 0 240 240">
            <circle className="ring-track" cx="120" cy="120" r="104" />
            <circle
              className={`ring-fill${loading ? ' scanning' : ''}`}
              cx="120" cy="120" r="104"
              strokeDasharray={CIRC}
              strokeDashoffset={loading ? 400 : ringOffset}
              style={result ? { stroke: catColor, filter: `drop-shadow(0 0 12px ${catColor})` } : {}}
            />
          </svg>

          {/* Inner circle */}
          <div className="ring-inner">

            {/* Idle */}
            {!preview && !loading && !result && (
              <>
                <div className="ring-idle-icon-wrap">
                  <span className="ring-idle-icon">📷</span>
                  <div className="ring-idle-pulse" />
                </div>
                <span className="ring-idle-label">Tap to scan waste</span>
                <span className="ring-idle-sub">or drag & drop</span>
              </>
            )}

            {/* Preview selected */}
            {preview && !loading && !result && (
              <img src={preview} alt="preview" className="ring-inner-img" />
            )}

            {/* Loading */}
            {loading && (
              <div className="ring-scan-overlay">
                {preview && <img src={preview} alt="scanning" className="ring-inner-img ring-inner-img-blur" />}
                <div className="ring-holo-beam" />
                <div className="ring-scan-line" />
                <span className="ring-scan-text">ANALYSING</span>
                <div className="ring-scan-dots">
                  <span /><span /><span />
                </div>
              </div>
            )}

            {/* Result */}
            {result && (
              <>
                {preview && <img src={preview} alt="scanned" className="ring-inner-img" />}
                <div className="ring-result-overlay" style={{ '--cat-color': catColor }}>
                  <span className="ring-result-icon">{catIcon}</span>
                  <span className="ring-result-cat" style={{ color: catColor }}>{result.category}</span>
                </div>
              </>
            )}
          </div>
        </div>

        {/* Status text */}
        <div className="ring-status">
          {!preview && !loading && !result && (
            <>
              <div className="ring-status-main">Ready to Scan</div>
              <div className="ring-status-sub">JPG · PNG · WEBP · Drag & Drop</div>
            </>
          )}
          {preview && !loading && !result && (
            <>
              <div className="ring-status-main">Image Ready</div>
              <div className="ring-status-sub">Hit Classify to analyse →</div>
            </>
          )}
          {loading && (
            <>
              <div className="ring-status-main" style={{ color: '#00D4FF' }}>Scanning…</div>
              <div className="ring-status-sub">AI model processing</div>
            </>
          )}
          {result && (
            <>
              <div className="ring-status-main" style={{ color: catColor }}>
                {confidence !== null ? `${(confidence * 100).toFixed(0)}% Confident` : 'Classified'}
              </div>
              <div className="ring-status-sub">{result.impact?.detectedObject || result.category}</div>
            </>
          )}
        </div>
      </section>

      {/* ── Error ── */}
      {error && (
        <div className="error-strip">
          <span>⚠</span> {error}
        </div>
      )}

      {/* ── Stat Cards ── */}
      <div className="home-stats-grid" data-reveal data-reveal-delay="100">
        <StatCard
          icon="🌫️" label="CO₂ Prevented"
          value={result ? result.co2Saved.toFixed(2) : '—'}
          unit="kg"
          active={!!result}
          barWidth={result ? Math.min(100, result.co2Saved * 100) : 0}
          sub={result ? 'This item' : 'Scan to see impact'}
          color="#00FF87"
        />
        <StatCard
          icon="🟢" label="Green Credits"
          value={result ? result.greenCredits : '—'}
          unit="pts"
          active={!!result}
          barWidth={result ? Math.min(100, result.greenCredits * 5) : 0}
          sub={result ? 'Earned now' : 'Awaiting scan'}
          color="#39FF14"
        />
        <StatCard
          icon="♻️" label="Category"
          value={result ? result.category : '—'}
          unit=""
          active={!!result}
          barWidth={0}
          sub={result ? (result.impact?.detectedObject || 'AI classified') : 'Pending'}
          color={catColor || '#00FF87'}
          mono={false}
        />
        <StatCard
          icon="🌳" label="Tree Equiv."
          value={result ? (result.impact?.treeDays ?? '—') : '—'}
          unit="days"
          active={!!result}
          barWidth={result ? Math.min(100, (result.impact?.treeDays || 0) * 20) : 0}
          sub={result ? 'CO₂ absorbed equiv.' : 'Awaiting scan'}
          color="#4ade80"
        />
      </div>

      {/* ── Action Buttons ── */}
      <div className="home-actions" data-reveal data-reveal-delay="180">
        {!preview && !result && (
          <>
            <label className="action-btn action-secondary" htmlFor="cam-input">
              <span className="action-icon">📷</span> Camera
              <input id="cam-input" type="file" accept="image/*" capture="environment" hidden onChange={handleFileChange} />
            </label>
            <label className="action-btn action-ghost" htmlFor="gal-input">
              <span className="action-icon">🖼</span> Upload
              <input id="gal-input" type="file" accept="image/*" hidden onChange={handleFileChange} />
            </label>
          </>
        )}
        {preview && !result && !loading && (
          <button className="action-btn action-primary action-full" onClick={handleSubmit}>
            <span className="action-btn-shimmer" />
            <span className="action-icon">🔍</span>
            Classify This Item
          </button>
        )}
        {result && (
          <button className="action-btn action-ghost action-full" onClick={handleReset}>
            <span className="action-icon">↩</span> Scan Another Item
          </button>
        )}
      </div>

      {/* ── Result Details ── */}
      {result && (
        <div style={{ animation: 'fadeUp .45s var(--ease-spring) both', paddingBottom: '8px' }}>
          <ResultCard
            category={result.category}
            impact={result.impact}
            ecoPoints={result.ecoPoints}
            bonusPoints={result.bonusPoints}
            greenCredits={result.greenCredits}
            co2Saved={result.co2Saved}
          />
          <ImpactPanel impact={result.impact} single />
        </div>
      )}

      {/* ── How It Works (idle only) ── */}
      {!preview && !result && (
        <section className="how-section" data-reveal data-reveal-delay="240">
          <div className="section-label">How It Works</div>
          <div className="how-steps">
            {[
              { n: '01', icon: '📡', title: 'Capture', desc: 'Tap the ring or drag & drop an image of your waste item.' },
              { n: '02', icon: '🧬', title: 'AI Analyses', desc: 'Our model classifies the waste type in milliseconds.' },
              { n: '03', icon: '🌱', title: 'Earn & Act', desc: 'Get disposal guidance, CO₂ data, and Green Credits.' },
            ].map((s, i) => (
              <div className="how-step" key={s.n} style={{ '--step-delay': `${i * 0.1}s` }}>
                <div className="step-orb">
                  <span className="step-orb-num">{s.n}</span>
                  <div className="step-orb-glow" />
                </div>
                <div className="step-content">
                  <div className="step-icon">{s.icon}</div>
                  <p className="step-title">{s.title}</p>
                  <p className="step-desc">{s.desc}</p>
                </div>
              </div>
            ))}
            {/* Dashed connector lines */}
            <div className="how-connector" />
          </div>
        </section>
      )}

      {/* ── Toast ── */}
      {toast && <div className={`toast ${toast.type}`}>{toast.msg}</div>}
    </div>
  );
}

function StatCard({ icon, label, value, unit, active, barWidth, sub, color, mono = true }) {
  return (
    <div className={`stat-card${active ? ' stat-card-active' : ''}`} style={{ '--sc': color }}>
      <div className="stat-card-header">
        <span className="stat-card-icon">{icon}</span>
        <span className="stat-card-label">{label}</span>
      </div>
      <div className="stat-card-value-row">
        <span className={`stat-card-value${mono ? ' stat-value-mono' : ''}`}>{value}</span>
        {unit && <span className="stat-card-unit">{unit}</span>}
      </div>
      {barWidth > 0 && (
        <div className="stat-bar">
          <div className="stat-bar-fill" style={{ width: `${barWidth}%`, background: color }} />
        </div>
      )}
      <div className="stat-card-sub">{sub}</div>
      {active && <div className="stat-card-corner-glow" />}
    </div>
  );
}
